"""Clean broker-style terminal HTML for ALPHA-GATE X.

This page is UI-only. It uses existing read-only market data and virtual paper
trading endpoints. It does not submit real broker orders.
"""

TERMINAL_HTML = r'''<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width,initial-scale=1" />
<title>ALPHA-GATE X Paper Terminal</title>
<style>
:root{color-scheme:dark;--bg:#050b13;--panel:#0b1728;--panel2:#0f2138;--line:rgba(148,163,184,.24);--text:#eef7ff;--muted:#9eb3cc;--cyan:#67e8f9;--green:#22c55e;--red:#ef4444;--yellow:#fbbf24;--shadow:0 24px 80px rgba(0,0,0,.42)}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 10% 0%,rgba(103,232,249,.16),transparent 34%),linear-gradient(135deg,#071426,#050b13);color:var(--text);font-family:Inter,system-ui,-apple-system,Segoe UI,sans-serif}.wrap{max-width:1180px;margin:0 auto;padding:14px 14px 48px}.top{position:sticky;top:0;z-index:40;display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin:0 -14px 14px;padding:10px 14px;background:rgba(5,10,18,.88);backdrop-filter:blur(16px);border-bottom:1px solid var(--line)}.badge{display:inline-flex;border-radius:999px;padding:7px 11px;background:rgba(103,232,249,.12);color:var(--cyan);font-size:.72rem;font-weight:950;letter-spacing:.06em;text-transform:uppercase}.green{background:rgba(34,197,94,.16);color:#bbf7d0}.red{background:rgba(239,68,68,.16);color:#fecaca}.yellow{background:rgba(251,191,36,.15);color:#fde68a}.hero{padding:6px 0 14px}h1{font-size:clamp(1.8rem,8vw,4.4rem);line-height:.98;margin:6px 0;letter-spacing:.04em;text-transform:uppercase}h2{margin:.2rem 0 .75rem;color:#b7f7d4}h3{margin:.15rem 0 .65rem}.muted{color:var(--muted)}.card{background:linear-gradient(180deg,rgba(15,33,56,.96),rgba(8,18,32,.96));border:1px solid var(--line);border-radius:22px;padding:15px;box-shadow:var(--shadow);margin:14px 0}.two{display:grid;grid-template-columns:1fr;gap:14px}.market{display:grid;grid-template-columns:1fr;gap:14px}.controls{display:grid;grid-template-columns:1fr;gap:10px}.field{display:grid;gap:6px}.field label{font-size:.74rem;font-weight:950;color:#dbeafe;text-transform:uppercase;letter-spacing:.05em}input,select,button,summary{width:100%;min-height:44px;border-radius:14px;border:1px solid var(--line);background:rgba(5,16,30,.92);color:var(--text);padding:11px 12px}button{font-weight:950;cursor:pointer}.primary{background:linear-gradient(135deg,rgba(103,232,249,.22),rgba(34,197,94,.16))}.danger{background:rgba(239,68,68,.18);color:#fecaca}.kv{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:9px}.kv>div{background:rgba(5,16,30,.72);border:1px solid var(--line);border-radius:14px;padding:10px;min-height:58px;overflow-wrap:anywhere}.kv strong{display:block;color:#dbeafe;font-size:.72rem;opacity:.9;text-transform:lowercase}.price{font-size:clamp(3rem,16vw,6.5rem);font-weight:1000;line-height:.95}.signal{font-size:clamp(2.7rem,14vw,6rem);font-weight:1000;line-height:.95}.buy{color:var(--green)}.sell{color:var(--red)}.warn{color:var(--yellow)}.profit{color:var(--green);font-weight:950}.loss{color:var(--red);font-weight:950}.meter{height:14px;border-radius:999px;background:#071523;border:1px solid var(--line);overflow:hidden}.meter>div{height:100%;width:0;background:linear-gradient(90deg,var(--red),var(--yellow),var(--green));transition:width .2s ease}.suggestbox{position:relative}.suggestions{display:none;position:absolute;left:0;right:0;top:100%;z-index:60;margin-top:4px;background:#071523;border:1px solid var(--line);border-radius:16px;max-height:260px;overflow:auto;box-shadow:var(--shadow)}.suggestion{padding:12px;border-bottom:1px solid var(--line);cursor:pointer}.suggestion:hover{background:rgba(103,232,249,.12)}canvas{width:100%;height:300px;background:#06111f;border:1px solid var(--line);border-radius:18px}.row{padding:9px 0;border-bottom:1px solid var(--line)}.row:last-child{border-bottom:none}pre{white-space:pre-wrap;overflow:auto;max-height:260px;background:#06111f;border-radius:14px;padding:12px}.tabs{display:flex;gap:8px;overflow:auto;margin:8px 0 14px}.tabs a{white-space:nowrap;text-decoration:none;color:var(--text);font-weight:950;border:1px solid var(--line);border-radius:999px;padding:9px 12px;background:rgba(5,16,30,.8)}@media(min-width:820px){.two,.market{grid-template-columns:1fr 1fr}.controls{grid-template-columns:repeat(2,1fr)}.wide{grid-column:1/-1}.kv{grid-template-columns:repeat(3,1fr)}}
</style>
</head>
<body>
<div class="wrap">
  <div class="top"><span class="badge green">CONNECTION READY</span><span class="badge green" id="polling">LIVE POLLING ON</span><span class="badge green">PAPER MODE</span><span class="badge red">REAL ORDERS DISABLED</span><span class="badge yellow" id="last-refresh">Last refresh: never</span></div>
  <section class="hero"><span class="badge">ALPHA-GATE X CLEAN TERMINAL</span><h1>Broker-Style Paper Trading Terminal</h1><p class="muted">Read-only market data + virtual paper trading. No real orders. No fake candles/signals.</p></section>
  <nav class="tabs"><a href="#market">Market</a><a href="#signal">Signal</a><a href="#order">Paper Order</a><a href="#auto">Auto Settings</a><a href="#account">Account</a><a href="#statement">Statement</a></nav>

  <section class="card" id="market"><h2>1. Search Stock / Index</h2><div class="field suggestbox"><label>Search Stock / Index</label><input id="symbol" value="RELIANCE" autocomplete="off" placeholder="Search RELIANCE, TCS, NIFTY…" oninput="queueSymbolSearch(this.value)" onfocus="queueSymbolSearch(this.value)"/><div id="suggestions" class="suggestions"></div></div><div class="controls"><button class="primary" onclick="selectSymbol(document.getElementById('symbol').value)">Load Selected Stock</button><button onclick="refreshAll(false)">Refresh Now</button></div></section>

  <section class="market"><div class="card"><span class="badge yellow" id="quote-status">DATA_UNAVAILABLE</span><h2 id="quote-symbol">RELIANCE</h2><div class="price" id="ltp">--</div><p class="muted" id="change">Change unavailable</p><div class="kv" id="quote-kv"></div></div><div class="card"><h2>2. Candlestick Chart</h2><span class="badge yellow" id="chart-status">DATA_UNAVAILABLE</span><canvas id="chart-canvas" width="900" height="320"></canvas><p class="muted" id="chart-note">Real candles only. No fabricated chart data.</p></div></section>

  <section class="two" id="signal"><div class="card"><span class="badge yellow">Live Signal Engine</span><h2>3. Signal Beside Paper Order</h2><div class="signal warn" id="signal-decision">--</div><p id="signal-reasons" class="muted">Signal reasons appear here.</p><div class="meter"><div id="conf-meter"></div></div><p><strong>Confidence:</strong> <span id="confidence">0</span>%</p><div class="kv" id="signal-kv"></div><button id="use-signal" onclick="useSignalInOrder()" disabled>Use Signal in Paper Order</button><p class="muted" id="use-signal-note">BUY/SELL validated signal required.</p></div>
  <div class="card" id="order"><span class="badge green">Virtual Order Ticket</span><h2>4. Paper Order Ticket</h2><div class="controls"><div class="field suggestbox"><label>Stock / Index</label><input id="paper-symbol" value="RELIANCE" autocomplete="off" placeholder="Search RELIANCE, TCS, NIFTY…" oninput="queuePaperSearch(this.value)" onfocus="queuePaperSearch(this.value)"/><div id="paper-suggestions" class="suggestions"></div></div><div class="field"><label>BUY/SELL</label><select id="paper-side"><option>BUY</option><option>SELL</option></select></div><div class="field"><label>Order sizing</label><select id="paper-mode" onchange="updateOrderPreview()"><option value="QUANTITY">Quantity mode</option><option value="AMOUNT">Amount mode</option></select></div><div class="field"><label>Quantity</label><input id="paper-qty" type="number" value="1" min="1" oninput="updateOrderPreview()"/></div><div class="field"><label>Amount</label><input id="paper-amount" type="number" value="1000" min="1" step="50" oninput="updateOrderPreview()"/></div><div class="field"><label>Entry Price optional</label><input id="paper-entry" type="number" value="0" min="0" step="0.05" oninput="updateOrderPreview()"/></div><div class="field"><label>Stop Loss</label><input id="paper-sl" type="number" value="0" min="0" step="0.05"/></div><div class="field"><label>Target 1</label><input id="paper-t1" type="number" value="0" min="0" step="0.05"/></div><div class="field"><label>Target 2</label><input id="paper-t2" type="number" value="0" min="0" step="0.05"/></div></div><div class="kv" id="order-preview"></div><button class="primary" onclick="submitPaperOrder()">Submit Paper Order</button><pre id="order-result">Last order result will appear here.</pre></div></section>

  <section class="two"><div class="card" id="auto"><span class="badge yellow">Paper Auto-Trade</span><h2>5. Paper Auto Settings</h2><div class="controls"><div class="field"><label>Auto-trade ON/OFF</label><select id="auto-enabled"><option value="false">OFF</option><option value="true">ON</option></select></div><div class="field"><label>Position sizing</label><select id="sizing"><option>FIXED_QUANTITY</option><option>FIXED_AMOUNT</option></select></div><div class="field"><label>Fixed quantity</label><input id="fixed-qty" type="number" value="1" min="1"/></div><div class="field"><label>Fixed amount</label><input id="fixed-amount" type="number" value="1000" min="1"/></div><div class="field"><label>Target mode</label><select id="target-mode"><option>PERCENT</option><option>POINTS</option></select></div><div class="field"><label>Target value</label><input id="target-value" type="number" value="1" step="0.05"/></div><div class="field"><label>Stop loss mode</label><select id="sl-mode"><option>PERCENT</option><option>POINTS</option></select></div><div class="field"><label>Stop loss value</label><input id="sl-value" type="number" value="0.5" step="0.05"/></div><div class="field"><label>Max open positions</label><input id="max-open" type="number" value="1" min="1"/></div><div class="field"><label>Max trades per day</label><input id="max-trades" type="number" value="5" min="1"/></div><div class="field"><label>Max daily paper loss</label><input id="max-loss" type="number" value="1000" min="0"/></div></div><button class="primary" onclick="saveSettings()">Save Settings</button><div class="kv" id="auto-preview"></div></div>
  <div class="card" id="account"><span class="badge green">Paper Account</span><h2>6. Paper Account</h2><div class="kv" id="paper-summary"></div><div class="controls"><div class="field"><label>Add virtual balance</label><input id="add-balance" type="number" value="10000" min="1" step="100"/></div><button onclick="addBalance()">Add Virtual Balance</button><button class="danger" onclick="resetPaper()">Reset Paper Account</button></div></div></section>

  <section class="two" id="statement"><div class="card"><h2>7. Open Positions</h2><div id="open-positions" class="muted">No open paper positions.</div></div><div class="card"><h2>8. Closed Trades</h2><div id="closed-trades" class="muted">No closed trades.</div></div><div class="card wide"><h2>9. Paper Statement Ledger</h2><div id="ledger" class="muted">No ledger entries yet.</div><details><summary>Show Debug JSON</summary><pre id="debug-json">Debug JSON will appear here.</pre></details></div></section>
</div>
<script>
let selectedSymbol='RELIANCE',lastQuote={},lastSignal={},symbolTimer=null,paperTimer=null;
const $=id=>document.getElementById(id);const fmt=x=>x===undefined||x===null?'DATA_UNAVAILABLE':x;const post=(u,p)=>fetch(u,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(p||{})}).then(r=>r.json());
function kv(id,obj,keys){$(id).innerHTML=keys.map(k=>`<div><strong>${k}</strong>${fmt(obj&&obj[k])}</div>`).join('')}
function stamp(){ $('last-refresh').textContent='Last refresh: '+new Date().toLocaleTimeString() }
function clean(v){return (v||'RELIANCE').trim().toUpperCase()}
function searchSymbols(q,target){q=clean(q);fetch('/api/market/symbols?q='+encodeURIComponent(q)).then(r=>r.json()).then(p=>{const box=$(target),syms=(p.symbols||[]).slice(0,50);box.innerHTML=syms.map(s=>`<div class="suggestion" onclick="pickSymbol('${s}')">${s}</div>`).join('');box.style.display=syms.length?'block':'none'})}
function queueSymbolSearch(q){clearTimeout(symbolTimer);symbolTimer=setTimeout(()=>searchSymbols(q,'suggestions'),250)}function queuePaperSearch(q){clearTimeout(paperTimer);paperTimer=setTimeout(()=>searchSymbols(q,'paper-suggestions'),250)}function pickSymbol(s){selectSymbol(s);$('suggestions').style.display='none';$('paper-suggestions').style.display='none'}
function selectSymbol(s){selectedSymbol=clean(s);$('symbol').value=selectedSymbol;$('paper-symbol').value=selectedSymbol;refreshAll(false)}
function refreshQuote(){return fetch('/api/market/quote?symbol='+encodeURIComponent(selectedSymbol)).then(r=>r.json()).then(p=>{lastQuote=p;$('quote-symbol').textContent=p.symbol||selectedSymbol;$('ltp').textContent=fmt(p.ltp);$('change').textContent=p.change_percent&&p.change_percent!=='DATA_UNAVAILABLE'?p.change_percent+'%':'Change unavailable';$('quote-status').textContent=p.validation_status||'DATA_UNAVAILABLE';kv('quote-kv',p,['open','high','low','close','volume','last_update','validation_status','data_source']);stamp();updateOrderPreview()})}
function refreshChart(){return fetch('/api/market/history?symbol='+encodeURIComponent(selectedSymbol)+'&interval=minute').then(r=>r.json()).then(p=>{drawCandles(p.candles||[]);$('chart-status').textContent=p.validation_status==='VALIDATED'?'CHART READY':'DATA_UNAVAILABLE';$('chart-note').textContent=p.validation_status==='VALIDATED'?'Showing real candles for '+selectedSymbol:'DATA_UNAVAILABLE. No fabricated chart data.'})}
function drawCandles(c){const canvas=$('chart-canvas'),ctx=canvas.getContext('2d');ctx.clearRect(0,0,canvas.width,canvas.height);ctx.fillStyle='#06111f';ctx.fillRect(0,0,canvas.width,canvas.height);let rows=c.map(x=>({o:+x.open,h:+x.high,l:+x.low,c:+x.close})).filter(x=>[x.o,x.h,x.l,x.c].every(Number.isFinite)).slice(-80);if(!rows.length){ctx.fillStyle='#9db3cc';ctx.font='25px system-ui';ctx.fillText('Live candle data unavailable',44,150);return}let max=Math.max(...rows.map(x=>x.h)),min=Math.min(...rows.map(x=>x.l)),range=Math.max(max-min,1),L=34,R=canvas.width-34,T=24,B=canvas.height-34,step=(R-L)/rows.length,y=p=>B-((p-min)/range)*(B-T);rows.forEach((x,i)=>{let xx=L+i*step+step/2,o=y(x.o),cl=y(x.c),h=y(x.h),l=y(x.l);ctx.strokeStyle=x.c>=x.o?'#22c55e':'#ef4444';ctx.fillStyle=ctx.strokeStyle;ctx.beginPath();ctx.moveTo(xx,h);ctx.lineTo(xx,l);ctx.stroke();ctx.fillRect(xx-3,Math.min(o,cl),6,Math.max(2,Math.abs(cl-o)))})}
function refreshSignal(){return fetch('/api/signal/live?symbol='+encodeURIComponent(selectedSymbol)).then(r=>r.json()).then(p=>{lastSignal=p;let d=p.decision||'DATA_UNAVAILABLE';$('signal-decision').textContent=d;$('signal-decision').className='signal '+(d==='BUY'?'buy':d==='SELL'?'sell':'warn');$('signal-reasons').textContent=(p.signal_reasons||[]).join(' · ')||'No reasons';$('confidence').textContent=p.confidence_score||0;$('conf-meter').style.width=Math.max(0,Math.min(100,+(p.confidence_score||0)))+'%';kv('signal-kv',p,['entry','stop_loss','target_1','target_2','risk_reward','validation_status','data_source']);let ok=(d==='BUY'||d==='SELL')&&p.validation_status==='VALIDATED';$('use-signal').disabled=!ok;$('use-signal-note').textContent=ok?'Signal can fill paper order.':'NO_TRADE/HOLD/DATA_UNAVAILABLE cannot fill order.';loadSettings()})}
function useSignalInOrder(){if(!$('use-signal').disabled){$('paper-side').value=lastSignal.decision;$('paper-entry').value=Number(lastSignal.entry||0);$('paper-sl').value=Number(lastSignal.stop_loss||0);$('paper-t1').value=Number(lastSignal.target_1||0);$('paper-t2').value=Number(lastSignal.target_2||0);updateOrderPreview()}}
function ltp(){let n=Number(lastQuote.ltp||0);return Number.isFinite(n)?n:0}function calcQty(){let mode=$('paper-mode').value,price=Number($('paper-entry').value||0)||ltp();return mode==='AMOUNT'?(price>0?Math.floor(Number($('paper-amount').value||0)/price):0):Number($('paper-qty').value||0)}
function updateOrderPreview(){let price=Number($('paper-entry').value||0)||ltp(),qty=calcQty(),value=price&&qty?+(price*qty).toFixed(2):0;kv('order-preview',{selected_symbol:clean($('paper-symbol').value),latest_ltp:price||'DATA_UNAVAILABLE',order_mode:$('paper-mode').value,calculated_quantity:qty,estimated_order_value:value,available_paper_cash:'see account'},['selected_symbol','latest_ltp','order_mode','calculated_quantity','estimated_order_value','available_paper_cash'])}
function submitPaperOrder(){post('/api/paper/order',{symbol:clean($('paper-symbol').value),side:$('paper-side').value,quantity:calcQty(),entry_price:Number($('paper-entry').value||0),stop_loss:Number($('paper-sl').value||0),target_1:Number($('paper-t1').value||0),target_2:Number($('paper-t2').value||0)}).then(p=>{$('order-result').textContent=JSON.stringify(p,null,2);loadPaper()})}
function settingsPayload(){return{paper_auto_trade_enabled:$('auto-enabled').value==='true',sizing_mode:$('sizing').value,fixed_quantity:Number($('fixed-qty').value),fixed_amount:Number($('fixed-amount').value),target_mode:$('target-mode').value,target_value:Number($('target-value').value),stop_loss_mode:$('sl-mode').value,stop_loss_value:Number($('sl-value').value),max_open_positions:Number($('max-open').value),max_trades_per_day:Number($('max-trades').value),max_daily_loss:Number($('max-loss').value)}}
function saveSettings(){post('/api/paper/settings',settingsPayload()).then(()=>loadSettings())}
function loadSettings(){fetch('/api/paper/settings?symbol='+encodeURIComponent(selectedSymbol)).then(r=>r.json()).then(p=>{let s=p.settings||{};$('auto-enabled').value=String(!!s.paper_auto_trade_enabled);$('sizing').value=s.sizing_mode||'FIXED_QUANTITY';$('fixed-qty').value=s.fixed_quantity||1;$('fixed-amount').value=s.fixed_amount||1000;$('target-mode').value=s.target_mode||'PERCENT';$('target-value').value=s.target_value||1;$('sl-mode').value=s.stop_loss_mode||'PERCENT';$('sl-value').value=s.stop_loss_value||0.5;$('max-open').value=s.max_open_positions||1;$('max-trades').value=s.max_trades_per_day||5;$('max-loss').value=s.max_daily_loss||1000;kv('auto-preview',p.auto_trade_preview||{},['requested','state','selected_symbol','latest_ltp','signal_decision','confidence_score','risk_reward','sizing_mode','calculated_quantity','generated_stop_loss','generated_target_1','generated_target_2','block_reasons'])})}
function loadPaper(){fetch('/api/paper/status').then(r=>r.json()).then(p=>{kv('paper-summary',p.account_summary||p,['cash_balance','equity','realized_pnl','unrealized_pnl','win_count','loss_count','win_rate','paper_auto_trade_state']);renderRows('open-positions',p.open_positions||[]);renderRows('closed-trades',p.closed_trades||[]);renderRows('ledger',p.statement_ledger||p.ledger_entries||[]);$('debug-json').textContent=JSON.stringify(p,null,2)})}
function renderRows(id,rows){$(id).innerHTML=rows.length?rows.slice(-20).reverse().map(r=>`<div class="row">${Object.entries(r).map(([k,v])=>`<strong>${k}:</strong> ${v}`).join(' · ')}</div>`).join(''):'None'}
function addBalance(){post('/api/paper/balance/add',{amount:Number($('add-balance').value||0)}).then(loadPaper)}function resetPaper(){post('/api/paper/reset',{}).then(loadPaper)}function refreshAll(light){refreshQuote();if(!light&&!document.hidden)refreshChart();refreshSignal();loadPaper();loadSettings()}
['paper-mode','paper-qty','paper-amount','paper-entry'].forEach(id=>$(id).addEventListener('input',updateOrderPreview));refreshAll(false);setInterval(()=>refreshQuote().then(loadPaper),2000);setInterval(refreshSignal,15000);setInterval(()=>{if(!document.hidden)refreshChart()},60000);setInterval(loadPaper,2000);
</script>
</body>
</html>'''
